$(function(){$(document).on("click","#submit",function(){$("#contactpage").validate({submitHandler:function(e){submitSignupFormNow($("#contactpage"))},rules:{fname:{required:!0},email:{required:!0,email:!0},phone:{required:!0,phone:!0}},errorElement:"span",errorPlacement:function(e,t){e.appendTo(t.parent())}}),submitSignupFormNow=function(e){var t=e.serialize();return $.ajax({url:"/index.php?rest_route=/phantom/v1/contact",type:"POST",data:t,dataType:"json",success:function(e){var t=$("<span>").text(e.msg||"Message sent").html();"Success"===e.status?$("#form_result").html('<span class="form-success alert alert-success d-block">'+t+"</span>"):$("#form_result").html('<span class="form-error alert alert-danger d-block">'+t+"</span>"),$("#form_result").show()}}),!1}})});